import{_ as e,o as a,c as i,a as n}from"./app.1b0dcdd7.js";const g=JSON.parse(`{"title":"Case History and Precedents","description":"","frontmatter":{},"headers":[{"level":2,"title":"TheOrangeWizard v. 14uu, Aug 2017","slug":"theorangewizard-v-14uu-aug-2017","link":"#theorangewizard-v-14uu-aug-2017","children":[]},{"level":2,"title":"1machinemaker1 v. 14uu, Aug 2017","slug":"_1machinemaker1-v-14uu-aug-2017","link":"#_1machinemaker1-v-14uu-aug-2017","children":[]},{"level":2,"title":"Crustifer v. SpicyBoy, Oct 2017","slug":"crustifer-v-spicyboy-oct-2017","link":"#crustifer-v-spicyboy-oct-2017","children":[]},{"level":2,"title":"Yoahtl v. 14uu, Oct 2017","slug":"yoahtl-v-14uu-oct-2017","link":"#yoahtl-v-14uu-oct-2017","children":[]},{"level":2,"title":"14uu v. 5point0, Nov 2017","slug":"_14uu-v-5point0-nov-2017","link":"#_14uu-v-5point0-nov-2017","children":[]},{"level":2,"title":"Yoahtl v. 1machinemaker1, Nov 2017","slug":"yoahtl-v-1machinemaker1-nov-2017","link":"#yoahtl-v-1machinemaker1-nov-2017","children":[]},{"level":2,"title":"Yoahtl v. Fran, Nov 2017","slug":"yoahtl-v-fran-nov-2017","link":"#yoahtl-v-fran-nov-2017","children":[]},{"level":2,"title":"Yoahtl v. Link2006, Nov 2017","slug":"yoahtl-v-link2006-nov-2017","link":"#yoahtl-v-link2006-nov-2017","children":[]},{"level":2,"title":"1machinemaker1 v. Yoahtl, Nov 2017","slug":"_1machinemaker1-v-yoahtl-nov-2017","link":"#_1machinemaker1-v-yoahtl-nov-2017","children":[]},{"level":2,"title":"Yoahtl v. TheOrangeWizard (and 14uu), Nov 2017","slug":"yoahtl-v-theorangewizard-and-14uu-nov-2017","link":"#yoahtl-v-theorangewizard-and-14uu-nov-2017","children":[]},{"level":2,"title":"meat312 v. daddy1015, Nov 2017","slug":"meat312-v-daddy1015-nov-2017","link":"#meat312-v-daddy1015-nov-2017","children":[]},{"level":2,"title":"ShinigamiFTW v. TheOrangeWizard, Nov 2017","slug":"shinigamiftw-v-theorangewizard-nov-2017","link":"#shinigamiftw-v-theorangewizard-nov-2017","children":[]},{"level":2,"title":"TheOrangeWizard v. ShinigamiFTW, Dec 2017","slug":"theorangewizard-v-shinigamiftw-dec-2017","link":"#theorangewizard-v-shinigamiftw-dec-2017","children":[]},{"level":2,"title":"WackyAki v. Meat312, Dec 2017","slug":"wackyaki-v-meat312-dec-2017","link":"#wackyaki-v-meat312-dec-2017","children":[]},{"level":2,"title":"Klasikrok v. TheOrangeWizard, Dec 2017","slug":"klasikrok-v-theorangewizard-dec-2017","link":"#klasikrok-v-theorangewizard-dec-2017","children":[]},{"level":2,"title":"Seekinq v. iOminous, Jan 2018","slug":"seekinq-v-iominous-jan-2018","link":"#seekinq-v-iominous-jan-2018","children":[]},{"level":2,"title":"TheOrangeWizard (and Amerikkalanein) v. AltRaid, Jan 2018","slug":"theorangewizard-and-amerikkalanein-v-altraid-jan-2018","link":"#theorangewizard-and-amerikkalanein-v-altraid-jan-2018","children":[]},{"level":2,"title":"Yoahtl v. iOminous, Jan 2018","slug":"yoahtl-v-iominous-jan-2018","link":"#yoahtl-v-iominous-jan-2018","children":[]},{"level":2,"title":"TheOrangeWizard v. ArowShot, Jan 2018","slug":"theorangewizard-v-arowshot-jan-2018","link":"#theorangewizard-v-arowshot-jan-2018","children":[]},{"level":2,"title":"bgbba v. Squareblob, Apr 2018","slug":"bgbba-v-squareblob-apr-2018","link":"#bgbba-v-squareblob-apr-2018","children":[]},{"level":2,"title":"Oddish (and GDAN) v. 5point0, Apr 2018","slug":"oddish-and-gdan-v-5point0-apr-2018","link":"#oddish-and-gdan-v-5point0-apr-2018","children":[]},{"level":2,"title":"TheOrangeWizard v. Quauhtli'n'Mia, Apr 2018","slug":"theorangewizard-v-quauhtli-n-mia-apr-2018","link":"#theorangewizard-v-quauhtli-n-mia-apr-2018","children":[]},{"level":2,"title":"Dr_Oracle v. TheOrangeWizard, May 2018","slug":"dr-oracle-v-theorangewizard-may-2018","link":"#dr-oracle-v-theorangewizard-may-2018","children":[]},{"level":2,"title":"Orinnari v. Wee786Harry, Jun 2018","slug":"orinnari-v-wee786harry-jun-2018","link":"#orinnari-v-wee786harry-jun-2018","children":[]},{"level":2,"title":"Wee786Harry v. Wingzero54, Jun 2018","slug":"wee786harry-v-wingzero54-jun-2018","link":"#wee786harry-v-wingzero54-jun-2018","children":[]},{"level":2,"title":"gbrb v. bgbba, Jun 2018","slug":"gbrb-v-bgbba-jun-2018","link":"#gbrb-v-bgbba-jun-2018","children":[]},{"level":2,"title":"meat312 v. TheOrangeWizard, Jun 2018","slug":"meat312-v-theorangewizard-jun-2018","link":"#meat312-v-theorangewizard-jun-2018","children":[]},{"level":2,"title":"Wee786Harry v. lil_wayne, Jun 2018","slug":"wee786harry-v-lil-wayne-jun-2018","link":"#wee786harry-v-lil-wayne-jun-2018","children":[]},{"level":2,"title":"meat312 v. Wee786Harry, Jun 2018","slug":"meat312-v-wee786harry-jun-2018","link":"#meat312-v-wee786harry-jun-2018","children":[]},{"level":2,"title":"TheOrangeWizard v. Quauhtli'n'Mia, Jul 2018","slug":"theorangewizard-v-quauhtli-n-mia-jul-2018","link":"#theorangewizard-v-quauhtli-n-mia-jul-2018","children":[]},{"level":2,"title":"Judges v. bgbba, Aug 2018","slug":"judges-v-bgbba-aug-2018","link":"#judges-v-bgbba-aug-2018","children":[]},{"level":2,"title":"bgbba v. TheOrangeWizard, Dec 2018","slug":"bgbba-v-theorangewizard-dec-2018","link":"#bgbba-v-theorangewizard-dec-2018","children":[]},{"level":2,"title":"Dill_Weasel v. TheOrangeWizard, Dec 2018","slug":"dill-weasel-v-theorangewizard-dec-2018","link":"#dill-weasel-v-theorangewizard-dec-2018","children":[]},{"level":2,"title":"Aki v. Sventhar, Oct 2019","slug":"aki-v-sventhar-oct-2019","link":"#aki-v-sventhar-oct-2019","children":[]},{"level":2,"title":"iOminous v. Yoahtl, Oct 2019","slug":"iominous-v-yoahtl-oct-2019","link":"#iominous-v-yoahtl-oct-2019","children":[]},{"level":2,"title":"Orinnari v. Aki, Feb 2020","slug":"orinnari-v-aki-feb-2020","link":"#orinnari-v-aki-feb-2020","children":[]},{"level":2,"title":"Aivius v. Charlieseeese, Dec 2020","slug":"aivius-v-charlieseeese-dec-2020","link":"#aivius-v-charlieseeese-dec-2020","children":[]},{"level":2,"title":"Yoahtl v. TheOrangeWizard, Apr 2021","slug":"yoahtl-v-theorangewizard-apr-2021","link":"#yoahtl-v-theorangewizard-apr-2021","children":[]},{"level":2,"title":"GDAN v. Miller, May 2021","slug":"gdan-v-miller-may-2021","link":"#gdan-v-miller-may-2021","children":[]},{"level":2,"title":"Okx v. spokey_dokey, Jun 2021","slug":"okx-v-spokey-dokey-jun-2021","link":"#okx-v-spokey-dokey-jun-2021","children":[]},{"level":2,"title":"Aki v. Shygdsamkd, Jun 2021","slug":"aki-v-shygdsamkd-jun-2021","link":"#aki-v-shygdsamkd-jun-2021","children":[]},{"level":2,"title":"Yoahtl v. NeoTide, Sep 2021","slug":"yoahtl-v-neotide-sep-2021","link":"#yoahtl-v-neotide-sep-2021","children":[]},{"level":2,"title":"Yoahtl v. Okx, Oct 2021","slug":"yoahtl-v-okx-oct-2021","link":"#yoahtl-v-okx-oct-2021","children":[]},{"level":2,"title":"GDAN v. Minemaster, Oct 2021","slug":"gdan-v-minemaster-oct-2021","link":"#gdan-v-minemaster-oct-2021","children":[]},{"level":2,"title":"Yoahtl v. Okx, Nov 2021","slug":"yoahtl-v-okx-nov-2021","link":"#yoahtl-v-okx-nov-2021","children":[]},{"level":2,"title":"Supremacy Clarification, Jan 2022","slug":"supremacy-clarification-jan-2022","link":"#supremacy-clarification-jan-2022","children":[]}],"relativePath":"government/court-cases-precedents/index.md","lastUpdated":1666985460000}`),t={name:"government/court-cases-precedents/index.md"},r=n('<h1 id="case-history-and-precedents" tabindex="-1">Case History and Precedents <a class="header-anchor" href="#case-history-and-precedents" aria-hidden="true">#</a></h1><p>This is a record of all the court cases in Yoahtl. Our court system works via an ever evolving set of decisions, by the Councillors acting in their capacity as judges in legal disputes. The precedent they set in court has the force of law, but can be challenged by concerned parties. If a separate judicial system were to arise, the existing case precedent would carry over to the new judiciary, since the courts would still be of the same legal essence. Not all decisions create precedent, only those trying new matters.</p><h2 id="theorangewizard-v-14uu-aug-2017" tabindex="-1"><a href="/government/court-cases-precedents/orange_v_14uu_aug_2017.html">TheOrangeWizard v. 14uu, Aug 2017</a> <a class="header-anchor" href="#theorangewizard-v-14uu-aug-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Confirmed the Extinction Rule that unauthorized construction except for underneath a plot one owned is not considered valid unless the Government has approved of the action.</li><li>Grief is to be punished by having the griefer clean it up.</li></ul><h2 id="_1machinemaker1-v-14uu-aug-2017" tabindex="-1"><a href="/government/court-cases-precedents/1machinemaker1_v_14uu_aug_2017.html">1machinemaker1 v. 14uu, Aug 2017</a> <a class="header-anchor" href="#_1machinemaker1-v-14uu-aug-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Restitution of all items in cases of two-sided disputes is standard practice.</li><li>The person found to be more guilty in a two-sided dispute can be put on probation (pearled and summoned) if the court believes them to have been at fault.</li></ul><h2 id="crustifer-v-spicyboy-oct-2017" tabindex="-1"><a href="/government/court-cases-precedents/crustifer_v_spicyboy_oct_2017.html">Crustifer v. SpicyBoy, Oct 2017</a> <a class="header-anchor" href="#crustifer-v-spicyboy-oct-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Theft will be met with forced restitution.</li><li>Searching a house for contraband is a valid tactic to find evidence for trials.</li><li>Repeated offenses of the same category can be punished more severely.</li></ul><h2 id="yoahtl-v-14uu-oct-2017" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_14uu_oct_2017.html">Yoahtl v. 14uu, Oct 2017</a> <a class="header-anchor" href="#yoahtl-v-14uu-oct-2017" aria-hidden="true">#</a></h2><h2 id="_14uu-v-5point0-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/14uu_v_5point0_nov_2017.html">14uu v. 5point0, Nov 2017</a> <a class="header-anchor" href="#_14uu-v-5point0-nov-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>An extreme imbalance of capability during a physical altercation means that the person in a stronger position has a responsibility to be more mature.</li><li>Meming is not an excuse for violence if both parties aren&#39;t in on the meme.</li></ul><h2 id="yoahtl-v-1machinemaker1-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_1machinemaker1_nov_2017.html">Yoahtl v. 1machinemaker1, Nov 2017</a> <a class="header-anchor" href="#yoahtl-v-1machinemaker1-nov-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Insubordination is defined as a refusal to follow instructions when working with public property, sanctioned or unsanctioned.</li><li>Roads count as public property.</li></ul><h2 id="yoahtl-v-fran-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_fran_nov_2017.html">Yoahtl v. Fran, Nov 2017</a> <a class="header-anchor" href="#yoahtl-v-fran-nov-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>If you are hired by a private citizen to do something and they tell you to stop, you stop.</li><li>It&#39;s not a deathtrap if it&#39;s not even finished and serving its intended purpose in the first place.</li></ul><h2 id="yoahtl-v-link2006-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_link2006_nov_2017.html">Yoahtl v. Link2006, Nov 2017</a> <a class="header-anchor" href="#yoahtl-v-link2006-nov-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li><p>No matter the charges, unless you are being directly attacked or the town is being griefed, or it is a hostile foreigner, no player other than Councillors or the Alcuahtl or any person occupying a position of authority to pearl legally authorized by the Council and Alcuahtl may pearl people.</p></li><li><p>If people plead guilty you retain the rights of a citizen unless the Judge explicitly denies them to you as a result of your actions.</p></li></ul><h2 id="_1machinemaker1-v-yoahtl-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/1machinemaker1_v_yoahtl_nov_2017.html">1machinemaker1 v. Yoahtl, Nov 2017</a> <a class="header-anchor" href="#_1machinemaker1-v-yoahtl-nov-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>The Alcuahtl cannot deny an appeal outright, only uphold the decision of the court or come to a new verdict.</li></ul><h2 id="yoahtl-v-theorangewizard-and-14uu-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_theorangewizard_(and_14uu)_nov_2017.html">Yoahtl v. TheOrangeWizard (and 14uu), Nov 2017</a> <a class="header-anchor" href="#yoahtl-v-theorangewizard-and-14uu-nov-2017" aria-hidden="true">#</a></h2><h2 id="meat312-v-daddy1015-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/meat312_v_daddy1015_nov_2017.html">meat312 v. daddy1015, Nov 2017</a> <a class="header-anchor" href="#meat312-v-daddy1015-nov-2017" aria-hidden="true">#</a></h2><h2 id="shinigamiftw-v-theorangewizard-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/shinigamiftw_v_theorangewizard_nov_2017.html">ShinigamiFTW v. TheOrangeWizard, Nov 2017</a> <a class="header-anchor" href="#shinigamiftw-v-theorangewizard-nov-2017" aria-hidden="true">#</a></h2><h2 id="theorangewizard-v-shinigamiftw-dec-2017" tabindex="-1"><a href="/government/court-cases-precedents/theorangewizard_v_shinigamiftw_dec_2017.html">TheOrangeWizard v. ShinigamiFTW, Dec 2017</a> <a class="header-anchor" href="#theorangewizard-v-shinigamiftw-dec-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Reparations from Government officials can&#39;t come from Government storage.</li></ul><h2 id="wackyaki-v-meat312-dec-2017" tabindex="-1"><a href="/government/court-cases-precedents/wackyaki_v_meat312_dec_2017.html">WackyAki v. Meat312, Dec 2017</a> <a class="header-anchor" href="#wackyaki-v-meat312-dec-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Vote buying is deemed illegitimate campaigning.</li></ul><h2 id="klasikrok-v-theorangewizard-dec-2017" tabindex="-1"><a href="/government/court-cases-precedents/klasikrok_v_theorangewizard_dec_2017.html">Klasikrok v. TheOrangeWizard, Dec 2017</a> <a class="header-anchor" href="#klasikrok-v-theorangewizard-dec-2017" aria-hidden="true">#</a></h2><h2 id="seekinq-v-iominous-jan-2018" tabindex="-1"><a href="/government/court-cases-precedents/seekinq_v_iominous_jan2018.html">Seekinq v. iOminous, Jan 2018</a> <a class="header-anchor" href="#seekinq-v-iominous-jan-2018" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Where a misrepresentation occurs in a disputed transaction, the terms may be adjusted to be as reasonable as possible but still must be within the scope of the original agreement.</li></ul><h2 id="theorangewizard-and-amerikkalanein-v-altraid-jan-2018" tabindex="-1"><a href="/government/court-cases-precedents/theorangewizard_(and_amerikkalanein)_v_altraid_jan_2018.html">TheOrangeWizard (and Amerikkalanein) v. AltRaid, Jan 2018</a> <a class="header-anchor" href="#theorangewizard-and-amerikkalanein-v-altraid-jan-2018" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li><p>Raid drills are not permitted unless authorised by the Alcuahtl, who must be aware of specific details. Ideally the populace is notified and informed, however this is not strictly required.</p></li><li><p>Precedent set as a result from a court case MUST take priority over Council or Alcuahtl decisions, especially informal decisions that are not voted-in Council Law. This is consistent with \u201CCouncil 5.3 What is criminal is established primarily through the arbitration of disputes by the courts, and secondarily through specific lines of Council Law.\u201D</p></li></ul><h2 id="yoahtl-v-iominous-jan-2018" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_iominous_jan_2018.html">Yoahtl v. iOminous, Jan 2018</a> <a class="header-anchor" href="#yoahtl-v-iominous-jan-2018" aria-hidden="true">#</a></h2><h2 id="theorangewizard-v-arowshot-jan-2018" tabindex="-1"><a href="/government/court-cases-precedents/theorangewizard_v_arowshot_jan_2018.html">TheOrangeWizard v. ArowShot, Jan 2018</a> <a class="header-anchor" href="#theorangewizard-v-arowshot-jan-2018" aria-hidden="true">#</a></h2><h2 id="bgbba-v-squareblob-apr-2018" tabindex="-1"><a href="/government/court-cases-precedents/bgbba_v_squareblob_apr_2018.html">bgbba v. Squareblob, Apr 2018</a> <a class="header-anchor" href="#bgbba-v-squareblob-apr-2018" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>There is no restriction on the Derelictor General&#39;s ability to derelict based on the property owner&#39;s resident or citizenship status.</li></ul><h2 id="oddish-and-gdan-v-5point0-apr-2018" tabindex="-1"><a href="/government/court-cases-precedents/oddish_(and_gdan)_v_5point0_apr_2018.html">Oddish (and GDAN) v. 5point0, Apr 2018</a> <a class="header-anchor" href="#oddish-and-gdan-v-5point0-apr-2018" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li><s>Defendants that refuse to choose a justice will be subject to a Bench Trial.</s></li></ul><h2 id="theorangewizard-v-quauhtli-n-mia-apr-2018" tabindex="-1"><a href="/government/court-cases-precedents/theorangewizard_v_quauhtli_n_mia_apr_2018.html">TheOrangeWizard v. Quauhtli&#39;n&#39;Mia, Apr 2018</a> <a class="header-anchor" href="#theorangewizard-v-quauhtli-n-mia-apr-2018" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Newcomers must receive Government approval prior to receiving residence and any citizens who give newcomers an apartment without prior Government approval will be punished with 90 minutes of manual labour.</li></ul><h2 id="dr-oracle-v-theorangewizard-may-2018" tabindex="-1"><a href="/government/court-cases-precedents/dr_oracle_v_theorangewizard_may_2018.html">Dr_Oracle v. TheOrangeWizard, May 2018</a> <a class="header-anchor" href="#dr-oracle-v-theorangewizard-may-2018" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Citizenship is revoked on grounds of unexplained inactivity or inactivity with insufficient explanation.</li><li>Improperly revoked citizenship must be restored.</li></ul><h2 id="orinnari-v-wee786harry-jun-2018" tabindex="-1"><a href="/government/court-cases-precedents/orinnari_v_wee786harry_jun_2018.html">Orinnari v. Wee786Harry, Jun 2018</a> <a class="header-anchor" href="#orinnari-v-wee786harry-jun-2018" aria-hidden="true">#</a></h2><h2 id="wee786harry-v-wingzero54-jun-2018" tabindex="-1"><a href="/government/court-cases-precedents/wee786harry_v_wingzero54_jun_2018.html">Wee786Harry v. Wingzero54, Jun 2018</a> <a class="header-anchor" href="#wee786harry-v-wingzero54-jun-2018" aria-hidden="true">#</a></h2><h2 id="gbrb-v-bgbba-jun-2018" tabindex="-1"><a href="/government/court-cases-precedents/gbrb_v_bgbba_jun_2018.html">gbrb v. bgbba, Jun 2018</a> <a class="header-anchor" href="#gbrb-v-bgbba-jun-2018" aria-hidden="true">#</a></h2><h2 id="meat312-v-theorangewizard-jun-2018" tabindex="-1"><a href="/government/court-cases-precedents/meat312_v_theorangewizard_jun_2018.html">meat312 v. TheOrangeWizard, Jun 2018</a> <a class="header-anchor" href="#meat312-v-theorangewizard-jun-2018" aria-hidden="true">#</a></h2><h2 id="wee786harry-v-lil-wayne-jun-2018" tabindex="-1"><a href="/government/court-cases-precedents/wee786harry_v_lil_wayne_jun_2018.html">Wee786Harry v. lil_wayne, Jun 2018</a> <a class="header-anchor" href="#wee786harry-v-lil-wayne-jun-2018" aria-hidden="true">#</a></h2><h2 id="meat312-v-wee786harry-jun-2018" tabindex="-1"><a href="/government/court-cases-precedents/meat312_v_wee786harry_jun_2018.html">meat312 v. Wee786Harry, Jun 2018</a> <a class="header-anchor" href="#meat312-v-wee786harry-jun-2018" aria-hidden="true">#</a></h2><h2 id="theorangewizard-v-quauhtli-n-mia-jul-2018" tabindex="-1"><a href="/government/court-cases-precedents/theorangewizard_v_quauhtli_n_mia_jul_2018.html">TheOrangeWizard v. Quauhtli&#39;n&#39;Mia, Jul 2018</a> <a class="header-anchor" href="#theorangewizard-v-quauhtli-n-mia-jul-2018" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li><p>In cases of stolen items, reparations shall only be granted on appeal if the goods have not been returned as ordered.</p></li><li><p>Whether the killed player had their bed set should be considered with regards to the reasonableness of the murder.</p></li></ul><h2 id="judges-v-bgbba-aug-2018" tabindex="-1"><a href="/government/court-cases-precedents/judges_v_bgbba_aug_2018.html">Judges v. bgbba, Aug 2018</a> <a class="header-anchor" href="#judges-v-bgbba-aug-2018" aria-hidden="true">#</a></h2><h2 id="bgbba-v-theorangewizard-dec-2018" tabindex="-1"><a href="/government/court-cases-precedents/bgbba_v_theorangewizard_dec_2018.html">bgbba v. TheOrangeWizard, Dec 2018</a> <a class="header-anchor" href="#bgbba-v-theorangewizard-dec-2018" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Limiting channel capacity, deleting channels, and banning specific citizens without just cause and consulting the rest of the Government (in cases where the action is not necessary as part of an emergency situation) will be considered a major violation of Article 1 of the Yoahtlan Bill of Rights. Should this occur by a Government member without appropriate permission, harsh penalties may be levied including (but not limited to) judicial review of the position holder&#39;s fitness for office.</li></ul><h2 id="dill-weasel-v-theorangewizard-dec-2018" tabindex="-1"><a href="/government/court-cases-precedents/dill_weasel_v_theorangewizard_dec_2018.html">Dill_Weasel v. TheOrangeWizard, Dec 2018</a> <a class="header-anchor" href="#dill-weasel-v-theorangewizard-dec-2018" aria-hidden="true">#</a></h2><h2 id="aki-v-sventhar-oct-2019" tabindex="-1"><a href="/government/court-cases-precedents/aki_v_sventhar_oct_2019.html">Aki v. Sventhar, Oct 2019</a> <a class="header-anchor" href="#aki-v-sventhar-oct-2019" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li><p><strong>(The Appellate Decision Article 2)</strong> The court has found it necessary to define two types of Harassment, In-Game Harassment (abv. IGH) and On-Discord Harassment (abv. ODH).</p><ul><li><p><strong>(A)</strong> In-Game Harassment shall be defined as:</p><p>Any actions taken within game towards another player that may cause emotional distress, actions that are directed with mal-intent, actions taken in retribution towards another player in a repeated manner, actions that may exclude players from the community due to racial, gender, sexual or other personal matters directed at individuals, and any other actions deemed offensive by the council either by consensus or law.</p><p>Examples of IGH would include:</p><ul><li><p>Saying or placing signs in game using slurs, repeated offensive name calling: e.g. racial slurs, homophobic sayings.</p></li><li><p>Repeatedly targeting players using actions that may be tiresome or annoying: e.g. nonstop snowball throwing, punching other players without the intent of murder.</p></li><li><p>Defacing others property</p></li><li><p>e.g. non-damaging grief</p></li><li><p>As well as any other actions deemed offensive by the council either by consensus or law.</p></li></ul></li><li><p><strong>(B)</strong> On-discord Harassment shall be defined as:</p><p>Any actions taken within game towards another player that may cause emotional distress, actions that are directed with mal-intent, actions taken in retribution towards another player in a repeated manner, actions that may exclude players from the community due to racial, gender, sexual or other personal matters directed at individuals, threatening direct messages, repeated spam, repeated bait-posting, harmful trolling, and repeated inconsiderate memeing. As well as any other actions deemed offensive by the council either by consensus or law.</p><p>Examples of ODH would include:</p><ul><li><p>Unessasscary name calling involving slurs or inappropriate language, e.g. Racial slurs directed at individuals</p></li><li><p>Spamming the discord with repeated messages or images directed to cause distress to individuals or the community, e.g. posting images multiple times of inappropriate material</p></li><li><p>The posting of certain material with or without intent that may elicit a negative emotional response. e.g. baiting an individual of a known trait to reply to a message in a manner that the individual finds he must \u201Cdefend\u201D his beliefs</p></li><li><p>Repeated Direct messages of a threatening nature involving in-game actions, e.g. blackmail, or leverage threats</p></li><li><p>As well as any other actions deemed offensive by the council either by consensus or law.</p></li></ul></li></ul></li><li><p><strong>(The Appellate Decision Article 3)</strong> The severity of harmful repeated actions shall be broken into three categories listed from least severe to most severe.</p><ul><li><p><strong>(1)</strong> Incidental Harassment: The least severe act of Harassment: any actions where the acting individual repeatedly creates acts that another player finds to be in a harassing manner, and the acting individual may not realize the acts to be in a harassing manner.</p></li><li><p><strong>(2)</strong> Minor Harassment: A moderate act of Harassment by an acting individual that causes distress to an individual, and the acting individual continues to repeat actions even after being repeatedly told to cease and desist harassing actions by the harassed individual or others.</p></li><li><p><strong>(3)</strong> Major Harassment: A severe act of Harassment by an acting individual done in a cruel and intentional manner done; with the intent of forcing someone to leave the community via means of repeated harassing acts, with the intent to cause someone great emotional distress, and/or with the intent of immense communal disruption.</p></li></ul></li><li><p><strong>(The Appellate Decision Article 4)</strong> Punishments for the act of Harassment</p><p>Punishments for the acts of harassment shall be based upon the severity of the act and issued upon precedent or manner befitting the severity of the act.</p><ul><li><p><strong>(Ruling 1)</strong> The court finds that expressions that are harassing in nature as defined in [The Appellate Decision Article 2] may not be considered freedom of expression.</p></li><li><p><strong>(Ruling 2)</strong> The court finds that membership of the discord platform is non-essential to membership of the in-game community.</p></li></ul></li></ul><h2 id="iominous-v-yoahtl-oct-2019" tabindex="-1"><a href="/government/court-cases-precedents/iominous_v_yoahtl_oct_2019.html">iOminous v. Yoahtl, Oct 2019</a> <a class="header-anchor" href="#iominous-v-yoahtl-oct-2019" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>If an injunction is filed against somebody\u2019s eligibility for council, they will be investigated and thus removed from the pool if found in breach of our laws and customs on the grounds of citizenship, positions of foreign offices, and non-primary residency for dual citizens, and questions about character and motives.</li></ul><h2 id="orinnari-v-aki-feb-2020" tabindex="-1"><a href="/government/court-cases-precedents/orinnari_v_aki_feb_2020.html">Orinnari v. Aki, Feb 2020</a> <a class="header-anchor" href="#orinnari-v-aki-feb-2020" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Abuses of Government Power ought to result in immediate removal from Government office.</li><li>One&#39;s citizenship may be temporarily suspended to ensure the fulfilment of a court sentence.</li></ul><h2 id="aivius-v-charlieseeese-dec-2020" tabindex="-1"><a href="/government/court-cases-precedents/aivius_v_charlieseeese_dec_2020.html">Aivius v. Charlieseeese, Dec 2020</a> <a class="header-anchor" href="#aivius-v-charlieseeese-dec-2020" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Yoahtlans concertedly attempting to recruit other Yoahtlans to foreign nations is to be considered harassment.</li></ul><h2 id="yoahtl-v-theorangewizard-apr-2021" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_theorangewizard_apr_2021.html">Yoahtl v. TheOrangeWizard, Apr 2021</a> <a class="header-anchor" href="#yoahtl-v-theorangewizard-apr-2021" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Time spent pearled prior to and during the trial can be considered time served if the sentence includes pearl time.</li></ul><h2 id="gdan-v-miller-may-2021" tabindex="-1"><a href="/government/court-cases-precedents/gdan_v_miller_may_2021.html">GDAN v. Miller, May 2021</a> <a class="header-anchor" href="#gdan-v-miller-may-2021" aria-hidden="true">#</a></h2><h2 id="okx-v-spokey-dokey-jun-2021" tabindex="-1"><a href="/government/court-cases-precedents/okx_v_spokey_dokey_jun_2021.html">Okx v. spokey_dokey, Jun 2021</a> <a class="header-anchor" href="#okx-v-spokey-dokey-jun-2021" aria-hidden="true">#</a></h2><h2 id="aki-v-shygdsamkd-jun-2021" tabindex="-1"><a href="/government/court-cases-precedents/aki_v_shygdsamkd_jun_2021.html">Aki v. Shygdsamkd, Jun 2021</a> <a class="header-anchor" href="#aki-v-shygdsamkd-jun-2021" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Time spent pearled during proceedings will not count as time served if the defendant is causing significant and deliberate delay.</li></ul><h2 id="yoahtl-v-neotide-sep-2021" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_neotide_sep_2021.html">Yoahtl v. NeoTide, Sep 2021</a> <a class="header-anchor" href="#yoahtl-v-neotide-sep-2021" aria-hidden="true">#</a></h2><h2 id="yoahtl-v-okx-oct-2021" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_okx_oct_2021.html">Yoahtl v. Okx, Oct 2021</a> <a class="header-anchor" href="#yoahtl-v-okx-oct-2021" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Secessions of unincorporated places do not violate Council Act 1.4.</li><li>Incidental pearlings do not violate the relevant Yoahtl v. Link2006, Nov 2017 precedent.</li></ul><h2 id="gdan-v-minemaster-oct-2021" tabindex="-1"><a href="/government/court-cases-precedents/gdan_v_minemaster_oct_2021.html">GDAN v. Minemaster, Oct 2021</a> <a class="header-anchor" href="#gdan-v-minemaster-oct-2021" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Pearl time can substitute grief-cleanup if it has already been cleaned up by someone else.</li></ul><h2 id="yoahtl-v-okx-nov-2021" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_okx_nov_2021.html">Yoahtl v. Okx, Nov 2021</a> <a class="header-anchor" href="#yoahtl-v-okx-nov-2021" aria-hidden="true">#</a></h2><h2 id="supremacy-clarification-jan-2022" tabindex="-1"><a href="/government/court-cases-precedents/supremacy_clarification_jan_2022.html">Supremacy Clarification, Jan 2022</a> <a class="header-anchor" href="#supremacy-clarification-jan-2022" aria-hidden="true">#</a></h2>',100),o=[r];function l(s,h,d,c,u,v){return a(),i("div",null,o)}const p=e(t,[["render",l]]);export{g as __pageData,p as default};
